use crate::configuration::UdtConfiguration;
use crate::control_packet::{AckOptionalInfo, ControlPacketType, HandShakeInfo, UdtControlPacket};
use crate::data_packet::{UdtDataPacket, UDT_DATA_HEADER_SIZE};
use crate::flow::{UdtFlow, PROBE_MODULO};
use crate::multiplexer::UdtMultiplexer;
use crate::packet::UdtPacket;
use crate::queue::{RcvBuffer, SndBuffer};
use crate::rate_control::RateControl;
use crate::seq_number::SeqNumber;
use crate::state::SocketState;
use crate::udt::{SocketRef, Udt, UDT_DEBUG};
use once_cell::sync::Lazy;
use rand::distributions::Alphanumeric;
use rand::Rng;
use sha2::{Digest, Sha256};
use std::cmp::Ordering;
use std::collections::BTreeSet;
use std::net::{IpAddr, SocketAddr};
use std::sync::{Arc, Mutex, RwLock, Weak};
use std::task::Poll;
use tokio::io::{Error, ErrorKind, ReadBuf, Result};
use tokio::sync::{Notify, RwLock as TokioRwLock};
use tokio::time::{Duration, Instant};

pub(crate) const SYN_INTERVAL: Duration = Duration::from_millis(10);
const MIN_EXP_INTERVAL: Duration = Duration::from_millis(300);
const PACKETS_BETWEEN_LIGHT_ACK: usize = 64;

static SALT: Lazy<String> = Lazy::new(|| {
    rand::thread_rng()
        .sample_iter(&Alphanumeric)
        .take(30)
        .map(char::from)
        .collect()
});

pub type SocketId = u32;

#[derive(Debug, Copy, Clone, PartialEq, Eq)]
pub enum SocketType {
    Stream = 1,
    Datagram = 2,
}

impl TryFrom<u32> for SocketType {
    type Error = Error;

    fn try_from(value: u32) -> Result<Self> {
        match value {
            1 => Ok(SocketType::Stream),
            2 => Ok(SocketType::Datagram),
            _ => Err(Error::new(
                ErrorKind::InvalidData,
                "unknown value for socket type",
            )),
        }
    }
}

#[derive(Debug)]
pub struct UdtSocket {
    pub socket_id: SocketId,
    pub status: Mutex<UdtStatus>,
    pub socket_type: SocketType,
    pub(crate) listen_socket: Option<SocketId>,
    peer_addr: Mutex<Option<SocketAddr>>,
    peer_socket_id: Mutex<Option<SocketId>>,
    pub initial_seq_number: SeqNumber,

    pub(crate) queued_sockets: TokioRwLock<BTreeSet<SocketId>>,
    pub(crate) accept_notify: Notify,
    pub(crate) multiplexer: RwLock<Weak<UdtMultiplexer>>,
    pub configuration: RwLock<UdtConfiguration>,

    rcv_buffer: Mutex<RcvBuffer>,
    snd_buffer: Mutex<SndBuffer>,
    flow: RwLock<UdtFlow>,
    pub rate_control: RwLock<RateControl>,
    start_time: Instant,

    state: Mutex<SocketState>,

    connect_notify: Notify,
    rcv_notify: Notify,
    ack_notify: Notify,
}

impl UdtSocket {
    pub(crate) fn new(
        socket_id: SocketId,
        socket_type: SocketType,
        isn: Option<SeqNumber>,
        configuration: Option<UdtConfiguration>,
    ) -> Self {
        let now = Instant::now();
        let initial_seq_number = isn.unwrap_or_else(SeqNumber::random);
        let configuration = configuration.unwrap_or_default();
        Self {
            socket_id,
            socket_type,
            status: Mutex::new(UdtStatus::Init),
            initial_seq_number,
            peer_addr: Mutex::new(None),
            peer_socket_id: Mutex::new(None),
            listen_socket: None,
            queued_sockets: TokioRwLock::new(BTreeSet::new()),
            accept_notify: Notify::new(),
            multiplexer: RwLock::new(Weak::new()),
            snd_buffer: Mutex::new(SndBuffer::new(configuration.snd_buf_size)),
            rcv_buffer: Mutex::new(RcvBuffer::new(
                configuration.rcv_buf_size,
                initial_seq_number,
            )),
            flow: RwLock::new(UdtFlow::default()),
            rate_control: RwLock::new(RateControl::new()),
            start_time: now,

            state: Mutex::new(SocketState::new(initial_seq_number, &configuration)),
            connect_notify: Notify::new(),
            rcv_notify: Notify::new(),
            ack_notify: Notify::new(),
            configuration: RwLock::new(configuration),
        }
    }

    pub fn with_peer(self, peer: SocketAddr, peer_socket_id: SocketId) -> Self {
        self.set_peer_addr(peer);
        *self.peer_socket_id.lock().unwrap() = Some(peer_socket_id);
        self
    }

use std::time::Duration;

const DEFAULT_MSS: u32 = 1500;
const DEFAULT_UDT_BUF_SIZE: u32 = 81920;
const DEFAULT_UDP_BUF_SIZE: usize = 8_000_000;
const UDT_VERSION: u32 = 4;

/// Options for UDT protocol
#[derive(Debug, Clone)]
pub struct UdtConfiguration {
    /// Packet size: the optimal size is the network MTU size. The default value is 1500 bytes.
    /// A UDT connection will choose the smaller value of the MSS between the two peer sides.
    pub mss: u32,
    /// Maximum window size (nb of packets).  
    /// Internal parameter: you should set it to not less than `rcv_buf_size`.
    /// Default: 256000
    pub flight_flag_size: u32,
    /// Size of temporary storage for packets to send (nb of packets)
    pub snd_buf_size: u32,
    /// Size of temporary storage for packets to receive (nb of packets)
    pub rcv_buf_size: u32,
    /// UDT uses UDP as the data channel, so the UDP buffer size may affect the performance.
    /// The sending buffer size is applied on the UDP socket. The actual value used
    /// by the kernel is bounded by "net.core.wmem_max".
    pub udp_snd_buf_size: usize,
    /// UDT uses UDP as the data channel, so the UDP buffer size may affect the performance.
    /// The receiving buffer size is applied on the UDP socket. The actual value used
    /// by the kernel is bounded by "net.core.rmem_max".
    pub udp_rcv_buf_size: usize,
    /// Whether SO_REUSEPORT option should be set on the UDP socket.
    /// On Linux, this option can be useful to load-balance packets
    /// from multiple clients to distinct threads and distinct UDT multiplexers.
    /// Default: false.
    pub udp_reuse_port: bool,
    /// Whether a potential existing UDT multiplexer (and associated UDP socket)
    /// should be reused when binding the same port. The preexisting listener
    /// must have been created with this option set to true.
    /// For optimal throughput from multiple clients, using
    /// `udp_reuse_port` may be preferable.
    /// Default: true
    pub reuse_mux: bool,
    /// UDT rendez-vous mode. (NOT IMPLEMENTED)
    pub rendezvous: bool,
    /// Maximum number of pending UDT connections to accept. Default: 1000
    pub accept_queue_size: usize,
    /// Linger time on close(). Default: 10 seconds
    pub linger_timeout: Option<Duration>,
}

impl UdtConfiguration {
    pub fn udt_version(&self) -> u32 {
        UDT_VERSION
    }
}

impl Default for UdtConfiguration {
    fn default() -> Self {
        Self {
            mss: DEFAULT_MSS,
            flight_flag_size: 256000,
            snd_buf_size: DEFAULT_UDT_BUF_SIZE,
            rcv_buf_size: DEFAULT_UDT_BUF_SIZE * 2,
            udp_snd_buf_size: DEFAULT_UDP_BUF_SIZE,
            udp_rcv_buf_size: DEFAULT_UDP_BUF_SIZE,
            udp_reuse_port: false,
            linger_timeout: Some(Duration::from_secs(10)),
            reuse_mux: true,
            rendezvous: false,
            accept_queue_size: 1000,
        }
    }
}

