26	
27	### UDT listener
28	
29	```rust,no_run
30	use std::net::Ipv4Addr;
31	use tokio::io::{AsyncReadExt, Result};
32	use tokio_udt::UdtListener;
33	
34	#[tokio::main]
35	async fn main() -> Result<()> {
36	    let port = 9000;
37	    let listener = UdtListener::bind((Ipv4Addr::UNSPECIFIED, port).into(), None).await?;
38	
39	    println!("Waiting for connections...");
40	
41	    loop {
42	        let (addr, mut connection) = listener.accept().await?;
43	        println!("Accepted connection from {}", addr);
44	        let mut buffer = Vec::with_capacity(1_000_000);
45	        tokio::task::spawn({
46	            async move {
47	                loop {
48	                    match connection.read_buf(&mut buffer).await {
49	                        Ok(_size) => {}
50	                        Err(e) => {
51	                            eprintln!("Connnection with {} failed: {}", addr, e);
52	                            break;
53	                        }
54	                    }
55	                }
56	            }
57	        });
58	    }
59	}
